for (uint256 i = 0; i < signers.length; ++i) {
    bytes memory signer = signers[i];
    require(isSigner(signer), MultiSignerERC7913NonexistentSigner(signer));

    uint64 weight = weights[i];
    require(weight > 0, MultiSignerERC7913WeightedInvalidWeight(signer, weight));

    unchecked {
        uint64 oldExtraWeight = $._extraWeights[signer];
        uint64 newExtraWeight = weight - 1;

        if (oldExtraWeight != newExtraWeight) {
            // Overflow impossible: weight values are bounded by uint64 and economic constraints
            extraWeightRemoved += oldExtraWeight;
            extraWeightAdded += $._extraWeights[signer] = newExtraWeight;
            emit ERC7913SignerWeightChanged(signer, weight);
        }
    }
}

if (params.tokenIn == address(0)) {
    // ETH sent in via msg.value
    require(msg.value == params.amountIn, "FSR:II"); // Insufficient input ETH
} else {
    if (params.v != 0) {
        // use permit instead of approval
        uint256 amount = params.approveMax
            ? type(uint256).max
            : params.amountIn;
        IERC20Permit(params.tokenIn).permit(
            msg.sender,
            address(this),
            amount,
            params.deadline,
            params.v,
            params.r,
            params.s
        );
    }
    // Pull tokens into the Router Contract
    TransferHelper.safeTransferFrom(
        params.tokenIn,
        msg.sender,
        address(this),
        params.amountIn
    );
}

if (fromDecimals_ < toDecimals_) {
    // Scale up: multiply by 10^(toDecimals - fromDecimals)
    uint256 scale = 10 ** decimalDiff;
    int256 scaleSigned = int256(scale);
    int256 result;
    // Use unchecked to prevent panic, then manually check for overflow
    unchecked {
        result = value_ * scaleSigned;
    }
    // Check for overflow: if value != 0, result / scale must equal value
    if (value_ != 0 && result / scaleSigned != value_) {
        revert TransientStorageMapperFuseSignedDecimalOverflow(value_, fromDecimals_, toDecimals_);
    }
    return result;
} else {
    // Scale down: divide by 10^(fromDecimals - toDecimals)
    uint256 scale = 10 ** decimalDiff;
    return value_ / int256(scale);
}

for (uint256 i; i < len; ++i) {
    fluidLendingStakingRewards = PlasmaVaultConfigLib.bytes32ToAddress(substrates[i]);
    if (fluidLendingStakingRewards == address(0)) {
        continue;
    }
    rewardsToken = IFluidLendingStakingRewards(fluidLendingStakingRewards).rewardsToken();
    rewardsTokenBalance = IFluidLendingStakingRewards(fluidLendingStakingRewards).earned(address(this));

    if (rewardsTokenBalance == 0) {
        continue;
    }

    IFluidLendingStakingRewards(fluidLendingStakingRewards).getReward();

    IERC20(rewardsToken).safeTransfer(rewardsClaimManager, rewardsTokenBalance);

    emit FluidInstadappClaimFuseRewardsClaimed(VERSION, rewardsToken, rewardsTokenBalance, rewardsClaimManager);
}

for (uint256 i = 0; i < len; ++i) {
    Validator storage validator = validators[validatorOwners[i]];
    ValidatorAttr memory validatorAttr;

    if (_isNextCommittee) {
        // Get the attributes that will be active in the next committee
        if (validator.lastSnapshotCommit < validatorsCommit) {
            validatorAttr = validator.latest;
        } else {
            validatorAttr = validator.snapshot;
        }
    } else {
        validatorAttr = _getValidatorAttributes(validator);
    }

    if (validatorAttr.active && !validatorAttr.removed) {
        committee[count] = CommitteeValidator({
            weight: validatorAttr.weight,
            leader: validatorAttr.leader,
            pubKey: validatorAttr.pubKey,
            proofOfPossession: validatorAttr.proofOfPossession
        });
        ++count;
    }
}

for (uint256 i = 0; i < signers.length; i++) {
  if (s_signers[signers[i]].active) revert RepeatedSigner();
  if (signers[i] == ZERO_ADDRESS) revert InvalidSigner();
  s_signers[signers[i]] = Signer({active: true, index: uint8(i)});

  transmitterAddress = transmitters[i];
  if (transmitterAddress == ZERO_ADDRESS) revert InvalidTransmitter();
  transmitter = s_transmitters[transmitterAddress];
  if (transmitter.active) revert RepeatedTransmitter();
  transmitter.active = true;
  transmitter.index = uint8(i);
  // new transmitters start afresh from current totalPremium
  // some spare change of premium from previous pool will be forfeited
  transmitter.lastCollected = s_hotVars.totalPremium;
  s_transmitters[transmitterAddress] = transmitter;
  if (mode == PayoutMode.OFF_CHAIN) {
    s_deactivatedTransmitters.remove(transmitterAddress);
  }
}

if (ocrConfigArgs.isSignatureVerificationEnabled) {
  _clearOracleRoles(ocrPluginType, ocrConfig.signers);

  address[] memory signers = ocrConfigArgs.signers;

  if (signers.length > MAX_NUM_ORACLES) revert InvalidConfig(InvalidConfigErrorType.TOO_MANY_SIGNERS);
  if (signers.length <= 3 * ocrConfigArgs.F) revert InvalidConfig(InvalidConfigErrorType.F_TOO_HIGH);
  // NOTE: Transmitters cannot exceed signers. Transmitters do not have to be >= 3F + 1 because they can match >= 3fChain + 1, where fChain <= F.
  // fChain is not represented in MultiOCR3Base - so we skip this check.
  if (signers.length < transmitters.length) revert InvalidConfig(InvalidConfigErrorType.TOO_MANY_TRANSMITTERS);

  configInfo.n = uint8(signers.length);
  ocrConfig.signers = signers;

  _assignOracleRoles(ocrPluginType, signers, Role.Signer);
}

if (
  resultCode == FunctionsResponse.FulfillResult.FULFILLED ||
  resultCode == FunctionsResponse.FulfillResult.USER_CALLBACK_ERROR
) {
  delete s_requestCommitments[requestId];
  // Reimburse the transmitter for the fulfillment gas cost
  s_withdrawableTokens[msg.sender] = gasOverheadJuels + callbackCostJuels;
  // Put donFee into the pool of fees, to be split later
  // Saves on storage writes that would otherwise be charged to the user
  s_feePool += commitment.donFee;
  emit RequestBilled({
    requestId: requestId,
    juelsPerGas: juelsPerGas,
    l1FeeShareWei: l1FeeShareWei,
    callbackCostJuels: callbackCostJuels,
    totalCostJuels: gasOverheadJuels + callbackCostJuels + commitment.donFee + commitment.adminFee
  });
}

if (liquidity > 0) {
    BalanceDelta liquidityDelta;
    // do not use _modifyLiquidity as we do not need to notify on modification for burns.
    ModifyLiquidityParams memory params = ModifyLiquidityParams({
        tickLower: info.tickLower(),
        tickUpper: info.tickUpper(),
        liquidityDelta: -(liquidity.toInt256()),
        salt: bytes32(tokenId)
    });
    (liquidityDelta, feesAccrued) = poolManager.modifyLiquidity(poolKey, params, hookData);
    emit ModifyPosition(
        poolKey.toId(), msgSender(), params.tickLower, params.tickUpper, params.liquidityDelta, params.salt
    );
    // Slippage checks should be done on the principal liquidityDelta which is the liquidityDelta - feesAccrued
    (liquidityDelta - feesAccrued).validateMinOut(amount0Min, amount1Min);
}

for (uint256 i = 0; i < signers.length; ++i) {
    bytes memory signer = signers[i];
    require(isSigner(signer), MultiSignerERC7913NonexistentSigner(signer));

    uint64 weight = weights[i];
    require(weight > 0, MultiSignerERC7913WeightedInvalidWeight(signer, weight));

    unchecked {
        uint64 oldExtraWeight = _extraWeights[signer];
        uint64 newExtraWeight = weight - 1;

        if (oldExtraWeight != newExtraWeight) {
            // Overflow impossible: weight values are bounded by uint64 and economic constraints
            extraWeightRemoved += oldExtraWeight;
            extraWeightAdded += _extraWeights[signer] = newExtraWeight;
            emit ERC7913SignerWeightChanged(signer, weight);
        }
    }
}

