if (signature.length == 65) {
    bytes32 r;
    bytes32 s;
    uint8 v;
    // ecrecover takes the signature parameters, and the only way to get them
    // currently is to use assembly.
    assembly {
        r := mload(add(signature, 0x20))
        s := mload(add(signature, 0x40))
        v := byte(0, mload(add(signature, 0x60)))
    }
    return tryRecover(hash, v, r, s);
} else if (signature.length == 64) {
    bytes32 r;
    bytes32 vs;
    // ecrecover takes the signature parameters, and the only way to get them
    // currently is to use assembly.
    assembly {
        r := mload(add(signature, 0x20))
        vs := mload(add(signature, 0x40))
    }
    return tryRecover(hash, r, vs);
} else {
    return (address(0), RecoverError.InvalidSignatureLength);
}

for (uint256 i = 0; i < rolesCount; i++) {
    previousSigner = signer;

    signer = LibAdmin._getSigner(signingHash, _stakeholders.signatures[i]);

    if (LibObject._getParentFromAddress(signer) != _stakeholders.entityIds[i]) {
        revert SimplePolicyStakeholderSignatureInvalid(
            signingHash,
            _stakeholders.signatures[i],
            LibHelpers._getIdForAddress(signer),
            LibObject._getParentFromAddress(signer),
            _stakeholders.entityIds[i]
        );
    }

    // Ensure there are no duplicate signers.
    if (previousSigner >= signer) {
        revert DuplicateSignerCreatingSimplePolicy(previousSigner, signer);
    }

    LibACL._assignRole(_stakeholders.entityIds[i], _policyId, _stakeholders.roles[i]);
}

if (_collToken == TokenUtils.WETH_ADDR) {
    bool isMaxPull = _params.collAmount == type(uint256).max;

    // when pulling max amount, we need to leave some WETH for gas compensation
    if (isMaxPull) {
        _params.collAmount = _collToken.pullTokensIfNeeded(_params.from, _params.collAmount);

        // This will revert on underflow anyway, added here to better communicate the error to the caller
        if (_params.collAmount <= ETH_GAS_COMPENSATION) {
            revert NotEnoughWethForCollateralAndGasCompensation(_params.collAmount);
        }
        _params.collAmount -= ETH_GAS_COMPENSATION;
    } else {
        _collToken.pullTokensIfNeeded(
            _params.from, _params.collAmount + ETH_GAS_COMPENSATION
        );
    }
} else {
    _params.collAmount = _collToken.pullTokensIfNeeded(_params.from, _params.collAmount);
    TokenUtils.WETH_ADDR.pullTokensIfNeeded(_params.from, ETH_GAS_COMPENSATION);
}

for (uint256 i = 0; i < previousRampsArgs.length; ++i) {
  PreviousRampsArgs calldata previousRampsArg = previousRampsArgs[i];

  PreviousRamps storage prevRamps = s_previousRamps[previousRampsArg.remoteChainSelector];

  // If the previous ramps are already set then they should not be updated.
  // In versions prior to the introduction of the NonceManager contract, nonces were tracked in the on/off ramps.
  // This config does a 1-time migration to move the nonce from on/off ramps into NonceManager
  if (prevRamps.prevOnRamp != address(0) || prevRamps.prevOffRamp != address(0)) {
    revert PreviousRampAlreadySet();
  }

  prevRamps.prevOnRamp = previousRampsArg.prevRamps.prevOnRamp;
  prevRamps.prevOffRamp = previousRampsArg.prevRamps.prevOffRamp;

  emit PreviousRampsUpdated(previousRampsArg.remoteChainSelector, previousRampsArg.prevRamps);
}

for (uint256 i = 0; i < sourceTokenAmounts.length; ++i) {
  Internal.SourceTokenData memory sourceTokenData =
    abi.decode(encodedSourceTokenData[i], (Internal.SourceTokenData));
  if (tokenGasOverrides.length != 0) {
    if (tokenGasOverrides[i] != 0) {
      sourceTokenData.destGasAmount = tokenGasOverrides[i];
    }
  }
  destTokenAmounts[i] = _releaseOrMintToken(
    sourceTokenAmounts[i].amount,
    originalSender,
    receiver,
    // This should never revert as the onRamp encodes the sourceTokenData struct. Only the inner components from
    // this struct come from untrusted sources.
    sourceTokenData,
    offchainTokenData[i]
  );

  if (s_rateLimitedTokensDestToSource.contains(destTokenAmounts[i].token)) {
    value += _getTokenValue(destTokenAmounts[i], IPriceRegistry(s_dynamicConfig.priceRegistry));
  }
}

for (uint256 i = 0; i < entries.length; i++) {
    Vm.DirEntry memory entry = entries[i];
    if (
        entry.path.contains(string.concat("/", vm.toString(chainId), "/")) && entry.path.contains(".json")
            && !entry.path.contains("dry-run")
    ) {
        runProcessed = true;
        string memory json = vm.readFile(entry.path);

        uint256 timestamp = vm.parseJsonUint(json, ".timestamp");

        if (timestamp > lastTimestamp) {
            latestAddress = processRun(json, contractName, latestAddress);

            // If we have found some deployed contract, update the timestamp
            // Otherwise, the earliest deployment may have been before `lastTimestamp` and we should not update
            if (latestAddress != address(0)) {
                lastTimestamp = timestamp;
            }
        }
    }
}

if (_value == 0) {
    _loadFarCallABIIntoActivePtr(_gas, _data, false, _isSystem);

    address callAddr = RAW_FAR_CALL_BY_REF_CALL_ADDRESS;
    assembly {
        success := call(_address, callAddr, 0, 0, 0xFFFF, 0, 0)
    }
} else {
    _loadFarCallABIIntoActivePtr(_gas, _data, false, true);

    // If there is provided `msg.value` call the `MsgValueSimulator` to forward ether.
    address msgValueSimulator = MSG_VALUE_SYSTEM_CONTRACT;
    address callAddr = SYSTEM_CALL_BY_REF_CALL_ADDRESS;
    // We need to supply the mask to the MsgValueSimulator to denote
    // that the call should be a system one.
    uint256 forwardMask = _isSystem ? MSG_VALUE_SIMULATOR_IS_SYSTEM_BIT : 0;

    assembly {
        success := call(msgValueSimulator, callAddr, _value, _address, 0xFFFF, forwardMask, 0)
    }
}

try vulcan.hevm.readFile(path) {
    return Ok(true);
} catch Error(string memory) {
    return Ok(false);
} catch (bytes memory reason) {
    bytes32 errorHash = keccak256(bytes(abi.decode(removeSelector(reason), (string))));
    string memory linuxErrorMessage =
        string.concat("The path \"", path, "\" is not allowed to be accessed for read operations.");
    bytes32 linuxErrorHash = keccak256(bytes(linuxErrorMessage));

    string memory macErrorMessage =
        string.concat("the path ", path, " is not allowed to be accessed for read operations");
    bytes32 macErrorHash = keccak256(bytes(macErrorMessage));
    if (errorHash == linuxErrorHash || errorHash == macErrorHash) {
        return FsErrors.Forbidden(linuxErrorMessage).toBoolResult();
    }
    return Ok(false);
}

while(true){
    hackBalances = [ SwappableToken(tokens[fromIndex]).balanceOf(address(this)),
                     SwappableToken(tokens[  toIndex]).balanceOf(address(this))];

    dexBalances = [SwappableToken(tokens[fromIndex]).balanceOf(address(dex)),
                   SwappableToken(tokens[  toIndex]).balanceOf(address(dex))];

    uint swapPrice = dex.get_swap_price(tokens[fromIndex], tokens[toIndex], hackBalances[0]);
    if(swapPrice > dexBalances[1]) {
        dex.swap(tokens[fromIndex], tokens[toIndex], dexBalances[0]);
        break;
    }else {
        dex.swap(tokens[fromIndex], tokens[toIndex], hackBalances[0]);
    }
    // reverse indexes
    fromIndex = 1 - fromIndex;
    toIndex = 1 - toIndex;
}

if (fullyAccrued) {
  dTokenExchangeRate = storedDTokenExchangeRate;
  cTokenExchangeRate = storedCTokenExchangeRate;
} else {
  // Only compute cToken exchange rate if it has not accrued this block.
  if (compute) {
    // Get current cToken exchange rate; inheriting contract overrides this.
    (cTokenExchangeRate,) = _getCurrentCTokenRates();
  } else {
    // Otherwise, get the stored cToken exchange rate.
    cTokenExchangeRate = CTokenInterface(_getCToken()).exchangeRateStored();
  }

  // Determine the cToken interest earned during the period.
  uint256 cTokenInterest = (
    (cTokenExchangeRate.mul(_SCALING_FACTOR)).div(storedCTokenExchangeRate)
  ).sub(_SCALING_FACTOR);

  // Calculate dToken exchange rate by applying 90% of the cToken interest.
  dTokenExchangeRate = storedDTokenExchangeRate.mul(
    _SCALING_FACTOR.add(cTokenInterest.mul(9) / 10)
  ) / _SCALING_FACTOR;
}

if (divertToAmo[underlyingToken]) {
    _flushToAmo(underlyingToken, amount);
} else {
    _updateFlow(underlyingToken);

    // total amount of collateral that the buffer controls in the alchemist
    uint256 localBalance = TokenUtils.safeBalanceOf(underlyingToken, address(this));

    // if there is not enough locally buffered collateral to meet the flow rate, exchange only the exchanged amount
    if (localBalance < flowAvailable[underlyingToken]) {
        currentExchanged[underlyingToken] += amount;
        ITransmuterV2(transmuter[underlyingToken]).exchange(amount);
    } else {
        uint256 exchangeable = flowAvailable[underlyingToken] - currentExchanged[underlyingToken];
        currentExchanged[underlyingToken] += exchangeable;
        ITransmuterV2(transmuter[underlyingToken]).exchange(exchangeable);
    }
}

if (rewards[vault].rewardAmount > 0) {
    // Calculates ratio of timeframe to time since last harvest
    // Uses this ratio to determine partial reward amount or extra reward amount
    uint256 blocksSinceLastReward = block.timestamp - rewards[vault].lastRewardTimestamp;
    uint256 maxReward = rewards[vault].rewardAmount - rewards[vault].rewardPaid;
    uint256 currentReward = rewards[vault].rewardAmount * blocksSinceLastReward / rewards[vault].rewardTimeframe;
    uint256 amountToSend = currentReward > maxReward ? maxReward : currentReward;

    TokenUtils.safeTransfer(IRewardCollector(rewards[vault].rewardCollectorAddress).rewardToken(), rewards[vault].rewardCollectorAddress, amountToSend);
    rewards[vault].lastRewardTimestamp = block.timestamp;
    rewards[vault].rewardPaid += amountToSend;

    if (rewards[vault].rewardPaid == rewards[vault].rewardAmount) {
        rewards[vault].rewardAmount = 0;
        rewards[vault].rewardPaid = 0;
    }
}

for (uint256 i; i < paramsLength; ++i) {
    address tokenAddr = params.tokens[i];
    uint256 allowance = params.allowances[i];
    calls[OPERATION_SET_APPROVAL_INDEX].data = abi.encodeWithSelector(
        IExecutable.execute.selector,
        abi.encode(
            SFSetApprovalData({
                asset: tokenAddr,
                delegate: params.spender,
                amount: allowance,
                sumAmounts: false
            })
        ),
        emptyParamMap
    );

    _sfExecute(params.sfProxy, calls);

    // Sanity check. Verify that the approval is actually set after execution through the summer.fi proxy
    _verifyThatApprovalIsSet(tokenAddr, params.sfProxy, params.spender, allowance);
}

if(global_collateral_ratio == 1e6) { // 1-to-1
            collat_out = collat_equivalent;
            fxs_out = 0;

        } else if (global_collateral_ratio == 0) { // Algorithmic
            fxs_out = getAmountOut(collat_equivalent, collat_virtual_reserves, fxs_virtual_reserves, redemption_fee); // switch FRAX to units of collateral and swap
            collat_out = 0;

            _update(fxs_virtual_reserves.sub(fxs_out), collat_virtual_reserves.add(collat_equivalent), fxs_virtual_reserves, collat_virtual_reserves);
        } else { // Fractional
            collat_out = collat_equivalent.mul(global_collateral_ratio).div(1e6);
            fxs_out = getAmountOut(collat_equivalent.mul((uint(1e6).sub(global_collateral_ratio))).div(1e6), collat_virtual_reserves, fxs_virtual_reserves, redemption_fee);

            _update(fxs_virtual_reserves.sub(fxs_out), collat_virtual_reserves.add(collat_equivalent.mul((uint(1e6).sub(global_collateral_ratio))).div(1e6)), fxs_virtual_reserves, collat_virtual_reserves);
        }

if (recipientManagementFeesLength > 0) {
    address[] memory managementFeeRecipientAddresses = new address[](recipientManagementFeesLength);

    for (uint256 i; i < recipientManagementFeesLength; i++) {
        managementFeeRecipientAddresses[i] = initData_.recipientManagementFees[i].recipient;

        if (initData_.recipientManagementFees[i].recipient == address(0)) {
            revert InvalidFeeRecipientAddress();
        }

        totalManagementFee += initData_.recipientManagementFees[i].feeValue;
        FeeManagerStorageLib.setManagementFeeRecipientFee(
            initData_.recipientManagementFees[i].recipient,
            initData_.recipientManagementFees[i].feeValue
        );
    }
    FeeManagerStorageLib.setManagementFeeRecipientAddresses(managementFeeRecipientAddresses);
}

if (recipientPerformanceFeesLength > 0) {
